var body = $json.body || $json;
var findings = body.findings || [];
var legalValidation = body.legalValidation || {};
var requirements = body.requirements || {};
var proposalAnalysis = body.proposalAnalysis || {};
var procurementInfo = body.procurementInfo || {};

var procStr = JSON.stringify(procurementInfo, null, 2).substring(0, 3000);
var reqStr = JSON.stringify(requirements, null, 2).substring(0, 20000);
var findingsStr = JSON.stringify(findings, null, 2).substring(0, 30000);
var legalStr = JSON.stringify(legalValidation, null, 2).substring(0, 20000);
var proposalStr = JSON.stringify(proposalAnalysis, null, 2).substring(0, 15000);

// Count stats
var compliant = 0, partial = 0, nonCompliant = 0, missing = 0;
for (var i = 0; i < findings.length; i++) {
  var s = findings[i].status;
  if (s === 'COMPLIANT') compliant++;
  else if (s === 'PARTIALLY_COMPLIANT') partial++;
  else if (s === 'NON_COMPLIANT') nonCompliant++;
  else if (s === 'MISSING') missing++;
}

var overallRec = (legalValidation.overall_recommendation || {}).action || 'НЕПОСОЧЕНО';

var p = 'Ти си секретар на комисия по обществена поръчка. Изготви МНОГО ПОДРОБЕН ПРОТОКОЛ от проверка на ТЕХНИЧЕСКОТО предложение.\n\n';
p += '## ИЗКЛЮЧИТЕЛНО ВАЖНО — ОБЕМ НА ПРОТОКОЛА\n';
p += 'Протоколът ТРЯБВА да е между 5 и 10 страници (приблизително 2500-5000 думи).\n';
p += 'Това е ЗАДЪЛЖИТЕЛНО изискване. Ако протоколът е по-кратък от 5 страници, добави ПОВЕЧЕ детайли:\n';
p += '- По-подробни цитати (дословни) от документацията И от предложението\n';
p += '- По-задълбочен анализ на всяко несъответствие\n';
p += '- По-обстойна правна обосновка\n';
p += '- Детайлен анализ на рисковете при обжалване\n\n';
p += '## ФОКУС: САМО ТЕХНИЧЕСКА ЧАСТ\n';
p += 'Протоколът е САМО за техническото предложение (работна програма, начин на изпълнение, методология, организация, екип, оборудване, график, качество, безопасност).\n';
p += 'НЕ споменавай: ЕЕДОП, ценово предложение, критерии за подбор, административни документи, финансова информация.\n\n';
p += '## ДАННИ ЗА ПОРЪЧКАТА:\n' + procStr + '\n\n';
p += '## СТАТИСТИКА:\n';
p += '- Общо проверени ТЕХНИЧЕСКИ изисквания: ' + findings.length + '\n';
p += '- Съответстващи (COMPLIANT): ' + compliant + '\n';
p += '- Частично съответстващи (PARTIALLY_COMPLIANT): ' + partial + '\n';
p += '- Несъответстващи (NON_COMPLIANT): ' + nonCompliant + '\n';
p += '- Липсващи (MISSING): ' + missing + '\n';
p += '- Обща препоръка от юридическия анализ: ' + overallRec + '\n\n';
p += '## ИЗВЛЕЧЕНИ ТЕХНИЧЕСКИ ИЗИСКВАНИЯ:\n' + reqStr + '\n\n';
p += '## АНАЛИЗ НА ТЕХНИЧЕСКОТО ПРЕДЛОЖЕНИЕ:\n' + proposalStr + '\n\n';
p += '## РЕЗУЛТАТИ ОТ КРЪСТОСАНА ПРОВЕРКА:\n' + findingsStr + '\n\n';
p += '## ЮРИДИЧЕСКА ВАЛИДАЦИЯ:\n' + legalStr + '\n\n';
p += '## СТРУКТУРА НА ПРОТОКОЛА (Markdown):\n\n';
p += '# ПРОТОКОЛ\n';
p += '## от проверка на техническо предложение\n';
p += '## по обществена поръчка с предмет: [от данните]\n\n';
p += '### I. Обща информация\n';
p += '- Предмет на поръчката\n';
p += '- Възложител\n';
p += '- Кандидат (ако е известен)\n';
p += '- Дата на проверката (днешна дата)\n';
p += '- Обхват: проверка на ТЕХНИЧЕСКОТО ПРЕДЛОЖЕНИЕ\n\n';
p += '### II. Обхват на проверката\n';
p += '- Общо проверени технически изисквания\n';
p += '- Кратко описание на методологията на проверката\n';
p += '- Какво се проверява (работна програма, методология, екип, оборудване, график и т.н.)\n\n';
p += '### III. Обобщена таблица на резултатите\n';
p += '| № | Техническо изискване | Тип | Статус | Оценка | Препоръка |\n';
p += '|---|---------------------|-----|--------|--------|-----------|\n';
p += '(за ВСЯКО ТЕХНИЧЕСКО изискване — кратък ред)\n\n';
p += '### IV. Подробен анализ на техническите изисквания\n';
p += 'Това е НАЙ-ВАЖНАТА и НАЙ-ДЪЛГАТА секция (3-6 страници!)\n\n';
p += 'За ВСЯКО изискване (включително COMPLIANT):\n';
p += '#### [N]. [Заглавие на изискването] — [СТАТУС]\n';
p += '**Изискване от документацията**: [ДОСЛОВЕН цитат — пълен текст]\n';
p += '**В техническото предложение на кандидата**: [ДОСЛОВЕН цитат от предложението / или "НЕ Е АДРЕСИРАНО"]\n';
p += '**Анализ**: [Подробен анализ — 3-5 изречения за PARTIALLY/NON_COMPLIANT, 1-2 за COMPLIANT]\n';
p += '**Недостатъци** (ако има): [списък с конкретни пропуски]\n';
p += '**Препоръка**: [ОТСТРАНЯВАНЕ / ЗАПИТВАНЕ ЗА РАЗЯСНЕНИЕ / НАМАЛЕНИ ТОЧКИ / СЪОТВЕТСТВА]\n\n';
p += '### V. Правна обосновка\n';
p += '- Подробна юридическа аргументация за всяко основание за отстраняване\n';
p += '- Конкретни членове и алинеи от ЗОП/ППЗОП\n';
p += '- Позоваване на чл. 107, ал. 1 и ал. 2 от ЗОП (ако е приложимо)\n';
p += '- Разграничение между формални нередовности и същностни несъответствия\n\n';
p += '### VI. Заключение и препоръка\n';
p += '**ПРЕПОРЪКА**: [ясна, еднозначна — ОТСТРАНЯВАНЕ / ДОПУСКАНЕ С БЕЛЕЖКИ / ДОПУСКАНЕ]\n';
p += 'Мотиви: [подробно обобщение с конкретни аргументи]\n\n';
p += '### VII. Рискове при обжалване пред КЗК\n';
p += '- Детайлна оценка на рисковете за ВСЯКО основание за отстраняване\n';
p += '- Възможни аргументи на кандидата\n';
p += '- Контрааргументи на комисията\n';
p += '- Препоръки за минимизиране на рисковете\n\n';
p += '---\n';
p += '*Забележка: Настоящият протокол е подготвен с помощта на AI анализ и подлежи на потвърждение от оценителната комисия.*\n\n';
p += '## КРИТИЧНИ ПРАВИЛА:\n';
p += '- Протоколът ТРЯБВА да е 5-10 страници (2500-5000 думи)\n';
p += '- ФОКУС САМО върху техническото предложение — НЕ споменавай ЕЕДОП, цена, подбор\n';
p += '- Цитирай ДОСЛОВНО от данните — не перифразирай\n';
p += '- Всяко заключение трябва да има КОНКРЕТНО правно основание\n';
p += '- Бъди обективен и балансиран\n';
p += '- Не добавяй констатации извън предоставените данни\n';
p += '- Протоколът трябва да е годен за официална употреба\n';
p += '- Пиши на правилен и формален български език';

return [{ json: { prompt: p } }];

var raw = ($json.text || $json.response || '').trim();

// If the response is wrapped in json/markdown blocks, extract
var reportText = raw;
var m = raw.match(/```(?:markdown)?\s*([\s\S]*?)```/);
if (m) reportText = m[1].trim();

// Basic cleanup
if (!reportText || reportText.length < 100) {
  reportText = '# ПРОТОКОЛ\n\nГрешка при генериране на протокола. Моля, прегледайте данните ръчно.\n';
}

return [{ json: { reportText: reportText } }];
